@namespace Lumeo

@{
    var context = new CollapsibleContext(Open, EventCallback.Factory.Create(this, Toggle), _triggerId, _contentId);
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Stable per-instance IDs so the trigger can render
    // aria-controls=ContentId and the content can render
    // aria-labelledby=TriggerId. Same pattern as Accordion.
    private readonly string _triggerId = LumeoIds.New("collapsible-trigger");
    private readonly string _contentId = LumeoIds.New("collapsible-content");

    private string CssClass => Cx.Merge(Class);

    private async Task Toggle()
    {
        var next = !Open;
        // Controlled (Open is bound via OpenChanged): let the parent own state —
        // fire the callback and render from the parent's next value instead of
        // mutating our own [Parameter], which desyncs if the parent rejects or
        // ignores the change. Uncontrolled: self-manage. (#238)
        if (OpenChanged.HasDelegate)
        {
            await OpenChanged.InvokeAsync(next);
        }
        else
        {
            Open = next;
        }
    }

    public record CollapsibleContext(bool IsOpen, EventCallback Toggle, string TriggerId, string ContentId);
}

@namespace Lumeo

@* `invisible` while closed — see AccordionContent: keeps the close animation
   while removing focusable children from the tab order. *@
<div id="@Context.ContentId" role="region" aria-labelledby="@Context.TriggerId" class="grid transition-[grid-template-rows] duration-200 ease-out @(Context.IsOpen ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0 invisible") @CssClass" @attributes="AdditionalAttributes" aria-hidden="@(Context.IsOpen ? "false" : "true")">
    <div class="overflow-hidden min-h-0">
        @ChildContent
    </div>
</div>

@code {
    [CascadingParameter] public Collapsible.CollapsibleContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Preserved for API compatibility only — Collapsible content is now
    /// always mounted so the grid-rows close animation can run on collapse,
    /// so this flag is effectively a no-op. Children always live in the DOM
    /// whether the collapsible is open or closed.
    /// </summary>
    [Parameter] public bool ForceMount { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge(Class);
}

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

<div id="@Context.TriggerId" class="@CssClass" role="button" tabindex="0" aria-expanded="@Context.IsOpen" aria-controls="@Context.ContentId" @onclick="Context.Toggle" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Collapsible.CollapsibleContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("cursor-pointer focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-sm", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            // div[role=button] has no native key synthesis: Space toggled AND
            // scrolled the page. Suppress only Space's default (Enter has no
            // default on a div) synchronously in JS.
            await Interop.RegisterPreventDefaultKeys(
                Context.TriggerId,
                new[] { new Lumeo.Services.PreventDefaultKeyRule(" ") });
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" || e.Key == " ")
        {
            await Context.Toggle.InvokeAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(Context.TriggerId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
